#include "audio_alert_system.h"
#include <driver/i2s.h>
#include <math.h>
#include <string.h>

#define SPK_WS   15
#define SPK_BCK  16
#define SPK_DOUT 17
#define SR       44100

static float g_vol = 1.0f;

void alert_setup() {
    i2s_config_t c = {};
    c.mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX);
    c.sample_rate = SR;
    c.bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT;
    c.channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT;
    c.communication_format = I2S_COMM_FORMAT_STAND_I2S;
    c.dma_buf_count = 8;
    c.dma_buf_len = 512;
    c.tx_desc_auto_clear = true;
    i2s_driver_install(I2S_NUM_1, &c, 0, NULL);
    i2s_pin_config_t p = { .bck_io_num=SPK_BCK, .ws_io_num=SPK_WS, .data_out_num=SPK_DOUT, .data_in_num=-1 };
    i2s_set_pin(I2S_NUM_1, &p);
    Serial.println("[alert] ready");
}

void alert_tone(float hz, int ms) {
    int N = SR * ms / 1000;
    int16_t buf[256];
    int fade = SR / 100;
    for (int i = 0; i < N; i += 256) {
        int chunk = (N - i < 256) ? N - i : 256;
        for (int j = 0; j < chunk; j++) {
            float a = g_vol * 0.7f;
            int idx = i + j;
            if (idx < fade) a *= (float)idx / fade;
            if (idx > N - fade) a *= (float)(N - idx) / fade;
            buf[j] = (int16_t)(sinf(2.0f * 3.14159f * hz * idx / SR) * a * 32767.0f);
        }
        size_t w = 0;
        i2s_write(I2S_NUM_1, buf, chunk * 2, &w, portMAX_DELAY);
    }
}

void alert_beep(int count, int on_ms, int off_ms) {
    for (int i = 0; i < count; i++) {
        alert_tone(1000, on_ms);
        if (i < count - 1) delay(off_ms);
    }
}

void alert_siren(float lo, float hi, int cycles, int ms) {
    int N = SR * ms / 1000;
    int16_t buf[256];
    for (int c = 0; c < cycles; c++) {
        for (int i = 0; i < N; i += 256) {
            int chunk = (N - i < 256) ? N - i : 256;
            float t = (float)(i) / N;
            float hz = lo + (hi - lo) * t;
            for (int j = 0; j < chunk; j++) {
                buf[j] = (int16_t)(sinf(2.0f * 3.14159f * hz * (i+j) / SR) * g_vol * 0.6f * 32767.0f);
            }
            size_t w = 0;
            i2s_write(I2S_NUM_1, buf, chunk * 2, &w, portMAX_DELAY);
        }
    }
}

void alert_melody(const float* notes, const int* durs, int count) {
    for (int i = 0; i < count; i++) {
        if (notes[i] > 0) alert_tone(notes[i], durs[i]);
        else delay(durs[i]);
    }
}

void alert_doorbell() {
    float n[] = {659.25f, 523.25f};
    int d[] = {200, 400};
    alert_melody(n, d, 2);
}

void alert_alarm() { alert_siren(800, 1600, 3, 500); }
void alert_success() {
    float n[] = {523.25f, 659.25f, 783.99f};
    int d[] = {100, 100, 200};
    alert_melody(n, d, 3);
}
void alert_error() {
    float n[] = {200, 0, 200};
    int d[] = {200, 100, 300};
    alert_melody(n, d, 3);
}

void alert_set_volume(int p) { g_vol = (float)(p < 0 ? 0 : (p > 200 ? 200 : p)) / 100.0f; }
void alert_stop() { int16_t s[64] = {0}; size_t w; i2s_write(I2S_NUM_1, s, 128, &w, 10); }
